// ---------------------------------------------------------------------------
// x402-aware fetch (viem signer + @x402/fetch wrapper)
// ---------------------------------------------------------------------------

function buildPayFetch() {
  const raw = process.env.WALLET_PRIVATE_KEY;
  if (!raw) throw new Error("Set WALLET_PRIVATE_KEY (a Base wallet holding USDC).");
  const pk = (raw.startsWith("0x") ? raw : `0x${raw}`) as `0x${string}`;
  const account = privateKeyToAccount(pk);
  const publicClient = createPublicClient({ chain: base, transport: viemHttp(RPC_URL) });
  const signer = toClientEvmSigner(
    {
      address: account.address,
      signTypedData: (message) => account.signTypedData(message as any),
    },
    publicClient,
  );
  const client = new x402Client();
  registerExactEvmScheme(client, { signer });
  return { fetch402: wrapFetchWithPayment(fetch, client), account };
}

// ---------------------------------------------------------------------------
// One paid x402 call to an agent. Returns the decoded Distill envelope + the
// unwrapped result (response.output.output).
// ---------------------------------------------------------------------------

async function callAgent(
  agentName: AgentName,
  payload: unknown,
  ctx: ReturnType<typeof buildPayFetch>,
): Promise<{ envelope: any; result: any }> {
  const agent = AGENTS[agentName];
  console.log(`\nAgent:  ${agentName} (${agent.priceUsdc} USDC)`);
  console.log(`URL:    ${agent.url}`);

  const body = JSON.stringify(payload);
  const headers: Record<string, string> = { "Content-Type": "application/json" };

  // wrapFetchWithPayment automates: send -> catch 402 -> read PAYMENT-REQUIRED
  // header -> sign EIP-3009 USDC transfer -> retry with PAYMENT-SIGNATURE header.
  const res = await ctx.fetch402(agent.url, { method: "POST", headers, body });
  console.log(`HTTP ${res.status}`);

  const payResp = res.headers.get("payment-response");
  if (payResp) {
    try {
      const decoded = JSON.parse(Buffer.from(payResp, "base64").toString("utf-8"));
      console.log("settlement tx:", decoded.transaction ?? decoded.txHash ?? "(see PAYMENT-RESPONSE)");
    } catch {
      /* non-JSON settlement header — ignore */
    }
  }

  const json = await res.json();
  // Distill envelope lives at response.output; real result at .output.output
  const envelope = (json as any).output ?? json;
  const result = (envelope as any).output ?? envelope;
  console.log("status:", (envelope as any).status);
  console.log("session_id:", (envelope as any).session_id);
  return { envelope, result };
}

// ---------------------------------------------------------------------------
// Main
//
// Calls Refine with the sample transaction batch, then prints the cleaned
// summary plus only the cascade rows flagged as bots.
// ---------------------------------------------------------------------------

async function main() {
  const ctx = buildPayFetch();
  console.log(`Payer:  ${ctx.account.address}`);

  const { result: refineResult } = await callAgent("refine", SAMPLE_PAYLOADS.refine, ctx);

  // Print the Refine summary and only the cascade rows flagged as bots, so the
  // terminal output stays readable instead of dumping every row.
  const cascadeRows: any[] = Array.isArray(refineResult?.cascade?.rows)
    ? refineResult.cascade.rows
    : [];
  const botRows = cascadeRows.filter((r) => r?.is_bot === true);
  console.log("\n========== Refine result ==========");
  console.log("summary:");
  console.log(JSON.stringify(refineResult?.summary ?? null, null, 2));
  console.log(`\nBots detected: ${botRows.length} out of ${cascadeRows.length} transactions`);
  console.log("\nbot rows (is_bot=true):");
  console.log(JSON.stringify(botRows, null, 2));
  console.log("===================================");
}

main().catch((err) => {
  console.error("Failed:", err?.message ?? err);
  process.exit(1);
});
